import '../quiz_question.dart';

const _subject = 'English Language';

QuizQuestion _vocabQ(String sentence, String word, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: "$sentence The word '$word' is nearest in meaning to:",
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

QuizQuestion _idiomQ(String sentence, List<String> options, String correct, String explanation) {
  return QuizQuestion(
    subject: _subject,
    text: sentence,
    options: options,
    correctIndex: options.indexOf(correct),
    explanation: explanation,
  );
}

